package com.dataprocessing.grpc;

import io.grpc.stub.StreamObserver;
import java.io.*;
import java.nio.file.*;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

public class FileServiceImpl extends FileServiceGrpc.FileServiceImplBase {

    private static final Logger logger = Logger.getLogger(FileServiceImpl.class.getName());
    private static final String STORAGE_DIR = "/tmp/grpc-uploads/";
    private static final int DEFAULT_CHUNK_SIZE = 64 * 1024; // 64KB chunks

    private final ConcurrentHashMap<String, String> fileRegistry = new ConcurrentHashMap<>();

    public FileServiceImpl() {
        try {
            Files.createDirectories(Paths.get(STORAGE_DIR));
        } catch (IOException e) {
            logger.log(Level.SEVERE, "Failed to create storage directory", e);
        }
    }

    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadResponse> responseObserver) {
        return new StreamObserver<FileChunk>() {
            private String fileId;
            private String filename;
            private OutputStream outputStream;
            private long bytesReceived = 0;
            private boolean initialized = false;

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (!initialized) {
                        fileId = UUID.randomUUID().toString();
                        filename = chunk.getFilename();
                        String storagePath = STORAGE_DIR + fileId + "_" + filename;
                        outputStream = new BufferedOutputStream(new FileOutputStream(storagePath));
                        fileRegistry.put(fileId, storagePath);
                        initialized = true;
                        logger.info("Started receiving file: " + filename + " with id: " + fileId);
                    }

                    byte[] data = chunk.getContent().toByteArray();
                    outputStream.write(data);
                    bytesReceived += data.length;

                    if (chunk.getTotalSize() > 0) {
                        double progress = (double) bytesReceived / chunk.getTotalSize() * 100;
                        logger.fine(String.format("Upload progress for %s: %.1f%%", fileId, progress));
                    }
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error writing chunk for file: " + fileId, e);
                    responseObserver.onError(
                            io.grpc.Status.INTERNAL
                                    .withDescription("Failed to write file chunk: " + e.getMessage())
                                    .asRuntimeException()
                    );
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.WARNING, "Upload error for file: " + fileId, t);
                cleanup();
            }

            @Override
            public void onCompleted() {
                try {
                    if (outputStream != null) {
                        outputStream.flush();
                        outputStream.close();
                    }
                    logger.info("Completed upload for file: " + fileId + ", bytes: " + bytesReceived);

                    UploadResponse response = UploadResponse.newBuilder()
                            .setFileId(fileId)
                            .setBytesReceived(bytesReceived)
                            .setSuccess(true)
                            .setMessage("File uploaded successfully")
                            .build();
                    responseObserver.onNext(response);
                    responseObserver.onCompleted();
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error finalizing upload for file: " + fileId, e);
                    responseObserver.onError(
                            io.grpc.Status.INTERNAL
                                    .withDescription("Failed to finalize upload: " + e.getMessage())
                                    .asRuntimeException()
                    );
                }
            }

            private void cleanup() {
                try {
                    if (outputStream != null) {
                        outputStream.close();
                    }
                    if (fileId != null) {
                        String path = fileRegistry.remove(fileId);
                        if (path != null) {
                            Files.deleteIfExists(Paths.get(path));
                        }
                    }
                } catch (IOException e) {
                    logger.log(Level.WARNING, "Error during cleanup", e);
                }
            }
        };
    }

    @Override
    public void downloadFile(DownloadRequest request, StreamObserver<FileChunk> responseObserver) {
        String fileId = request.getFileId();
        String filePath = fileRegistry.get(fileId);

        if (filePath == null) {
            responseObserver.onError(
                    io.grpc.Status.NOT_FOUND
                            .withDescription("File not found: " + fileId)
                            .asRuntimeException()
            );
            return;
        }

        int chunkSize = request.getChunkSize() > 0 ? (int) request.getChunkSize() : DEFAULT_CHUNK_SIZE;

        try (InputStream inputStream = new BufferedInputStream(new FileInputStream(filePath))) {
            File file = new File(filePath);
            long totalSize = file.length();
            String filename = file.getName();

            // Remove the UUID prefix from filename
            if (filename.contains("_")) {
                filename = filename.substring(filename.indexOf("_") + 1);
            }

            byte[] buffer = new byte[chunkSize];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                        .setFilename(filename)
                        .setContent(com.google.protobuf.ByteString.copyFrom(buffer, 0, bytesRead))
                        .setOffset(offset)
                        .setTotalSize(totalSize)
                        .build();

                responseObserver.onNext(chunk);
                offset += bytesRead;
            }

            logger.info("Completed download for file: " + fileId + ", total bytes: " + offset);
            responseObserver.onCompleted();

        } catch (IOException e) {
            logger.log(Level.SEVERE, "Error downloading file: " + fileId, e);
            responseObserver.onError(
                    io.grpc.Status.INTERNAL
                            .withDescription("Failed to read file: " + e.getMessage())
                            .asRuntimeException()
            );
        }
    }

    @Override
    public StreamObserver<DataMessage> processData(StreamObserver<DataMessage> responseObserver) {
        return new StreamObserver<DataMessage>() {

            @Override
            public void onNext(DataMessage message) {
                logger.info("Processing data message: " + message.getMessageId()
                        + ", type: " + message.getType()
                        + ", payload size: " + message.getPayload().size() + " bytes");

                try {
                    byte[] processedPayload = processPayload(message);

                    DataMessage response = DataMessage.newBuilder()
                            .setMessageId(UUID.randomUUID().toString())
                            .setType("PROCESSED_" + message.getType())
                            .setPayload(com.google.protobuf.ByteString.copyFrom(processedPayload))
                            .putAllHeaders(message.getHeadersMap())
                            .putHeaders("original-message-id", message.getMessageId())
                            .putHeaders("processing-status", "SUCCESS")
                            .setTimestamp(System.currentTimeMillis())
                            .build();

                    responseObserver.onNext(response);

                } catch (Exception e) {
                    logger.log(Level.SEVERE, "Error processing message: " + message.getMessageId(), e);

                    DataMessage errorResponse = DataMessage.newBuilder()
                            .setMessageId(UUID.randomUUID().toString())
                            .setType("ERROR")
                            .putHeaders("original-message-id", message.getMessageId())
                            .putHeaders("error", e.getMessage())
                            .setTimestamp(System.currentTimeMillis())
                            .build();

                    responseObserver.onNext(errorResponse);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.WARNING, "Bidirectional stream error", t);
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed");
                responseObserver.onCompleted();
            }

            private byte[] processPayload(DataMessage message) {
                // Simulated data processing - replace with actual business logic
                byte[] original = message.getPayload().toByteArray();
                byte[] result = new byte[original.length];
                for (int i = 0; i < original.length; i++) {
                    result[i] = (byte) (original[i] & 0xFF);
                }
                return result;
            }
        };
    }
}

