package com.dataprocessing.grpc;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;
import com.google.protobuf.ByteString;

import java.io.*;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.logging.Level;
import java.util.logging.Logger;

public class GrpcClient {

    private static final Logger logger = Logger.getLogger(GrpcClient.class.getName());
    private static final int CHUNK_SIZE = 64 * 1024; // 64KB

    private final ManagedChannel channel;
    private final FileServiceGrpc.FileServiceStub asyncStub;
    private final FileServiceGrpc.FileServiceBlockingStub blockingStub;

    public GrpcClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();

        asyncStub = FileServiceGrpc.newStub(channel);
        blockingStub = FileServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(10, TimeUnit.SECONDS);
    }

    /**
     * Upload a file using client streaming RPC.
     */
    public String uploadFile(String filePath) throws InterruptedException, IOException {
        final CountDownLatch latch = new CountDownLatch(1);
        final String[] resultFileId = {null};

        StreamObserver<UploadResponse> responseObserver = new StreamObserver<UploadResponse>() {
            @Override
            public void onNext(UploadResponse response) {
                logger.info("Upload response: fileId=" + response.getFileId()
                        + ", bytes=" + response.getBytesReceived()
                        + ", success=" + response.getSuccess()
                        + ", message=" + response.getMessage());
                resultFileId[0] = response.getFileId();
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Upload failed", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Upload stream completed");
                latch.countDown();
            }
        };

        StreamObserver<FileChunk> requestObserver = asyncStub.uploadFile(responseObserver);

        File file = new File(filePath);
        long totalSize = file.length();
        String filename = file.getName();

        try (InputStream inputStream = new BufferedInputStream(new FileInputStream(file))) {
            byte[] buffer = new byte[CHUNK_SIZE];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                        .setFilename(filename)
                        .setContent(ByteString.copyFrom(buffer, 0, bytesRead))
                        .setOffset(offset)
                        .setTotalSize(totalSize)
                        .build();

                requestObserver.onNext(chunk);
                offset += bytesRead;

                // Check if the RPC is still alive
                if (latch.getCount() == 0) {
                    // RPC completed or errored before we finished sending
                    return null;
                }
            }
        }

        requestObserver.onCompleted();
        latch.await(5, TimeUnit.MINUTES);

        return resultFileId[0];
    }

    /**
     * Download a file using server streaming RPC.
     */
    public void downloadFile(String fileId, String outputPath) throws InterruptedException {
        final CountDownLatch latch = new CountDownLatch(1);

        DownloadRequest request = DownloadRequest.newBuilder()
                .setFileId(fileId)
                .setChunkSize(CHUNK_SIZE)
                .build();

        asyncStub.downloadFile(request, new StreamObserver<FileChunk>() {
            private OutputStream outputStream;
            private long bytesReceived = 0;

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (outputStream == null) {
                        outputStream = new BufferedOutputStream(new FileOutputStream(outputPath));
                        logger.info("Downloading file: " + chunk.getFilename());
                    }

                    byte[] data = chunk.getContent().toByteArray();
                    outputStream.write(data);
                    bytesReceived += data.length;

                    if (chunk.getTotalSize() > 0) {
                        double progress = (double) bytesReceived / chunk.getTotalSize() * 100;
                        logger.fine(String.format("Download progress: %.1f%%", progress));
                    }
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error writing downloaded chunk", e);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Download failed", t);
                cleanup();
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                cleanup();
                logger.info("Download completed. Total bytes: " + bytesReceived);
                latch.countDown();
            }

            private void cleanup() {
                try {
                    if (outputStream != null) {
                        outputStream.flush();
                        outputStream.close();
                    }
                } catch (IOException e) {
                    logger.log(Level.WARNING, "Error closing output stream", e);
                }
            }
        });

        latch.await(5, TimeUnit.MINUTES);
    }

    /**
     * Bidirectional streaming for data processing.
     */
    public void processDataBidirectional(int messageCount) throws InterruptedException {
        final CountDownLatch latch = new CountDownLatch(1);

        StreamObserver<DataMessage> responseObserver = new StreamObserver<DataMessage>() {
            private int responsesReceived = 0;

            @Override
            public void onNext(DataMessage response) {
                responsesReceived++;
                logger.info("Received processed response #" + responsesReceived
                        + ": id=" + response.getMessageId()
                        + ", type=" + response.getType()
                        + ", payload size=" + response.getPayload().size()
                        + ", headers=" + response.getHeadersMap());
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Bidirectional stream error", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed. Total responses: " + responsesReceived);
                latch.countDown();
            }
        };

        StreamObserver<DataMessage> requestObserver = asyncStub.processData(responseObserver);

        try {
            for (int i = 0; i < messageCount; i++) {
                byte[] payload = generateSamplePayload(1024 * (i + 1)); // Increasing payload sizes

                DataMessage message = DataMessage.newBuilder()
                        .setMessageId(UUID.randomUUID().toString())
                        .setType("DATA_BATCH_" + i)
                        .setPayload(ByteString.copyFrom(payload))
                        .putHeaders("batch-index", String.valueOf(i))
                        .putHeaders("source", "data-processor-client")
                        .setTimestamp(System.currentTimeMillis())
                        .build();

                requestObserver.onNext(message);
                logger.info("Sent message #" + (i + 1) + " with payload size: " + payload.length);

                // Small delay to simulate real-world data generation
                Thread.sleep(100);
            }
        } catch (RuntimeException e) {
            requestObserver.onError(e);
            throw e;
        }

        requestObserver.onCompleted();
        latch.await(5, TimeUnit.MINUTES);
    }

    private byte[] generateSamplePayload(int size) {
        byte[] payload = new byte[size];
        for (int i = 0; i < size; i++) {
            payload[i] = (byte) (i % 256);
        }
        return payload;
    }

    public static void main(String[] args) throws Exception {
        GrpcClient client = new GrpcClient("localhost", 9090);

        try {
            // Example 1: Upload a file
            if (args.length > 0 && "upload".equals(args[0])) {
                String filePath = args.length > 1 ? args[1] : "test-file.dat";

                // Create a sample file if it doesn't exist
                if (!Files.exists(Paths.get(filePath))) {
                    logger.info("Creating sample file: " + filePath);
                    byte[] sampleData = new byte[10 * 1024 * 1024]; // 10MB
                    for (int i = 0; i < sampleData.length; i++) {
                        sampleData[i] = (byte) (i % 256);
                    }
                    Files.write(Paths.get(filePath), sampleData);
                }

                String fileId = client.uploadFile(filePath);
                logger.info("Uploaded file with ID: " + fileId);

                // Example 2: Download the file
                if (fileId != null) {
                    String downloadPath = "downloaded_" + Paths.get(filePath).getFileName();
                    client.downloadFile(fileId, downloadPath);
                    logger.info("Downloaded file to: " + downloadPath);
                }
            }

            // Example 3: Bidirectional streaming
            if (args.length == 0 || "process".equals(args[0])) {
                logger.info("Starting bidirectional data processing...");
                client.processDataBidirectional(5);
            }

        } finally {
            client.shutdown();
        }
    }
}

